use std::thread;

struct State {
    data: String,
}

fn recursive(state: &State) -> usize {
    let _ = state.data.clone();
    recursive(state)
}

fn main() {
    let s = State { data: "hello".to_string() };
    thread::spawn(move || recursive(&s)).join().unwrap();
